mapper.select:
select cc.user_id, cc.create_time, cc.phone, cc.name, cc.gender, cc.age, cc.merchant_id,
       cc.lock_flag, cc.verified, cmi.merchant_name as merchantName
from cm_customer cc
left join cm_merchant_info cmi on cc.merchant_id = cmi.id
where cc.del_flag = '0'

	and cc.phone = #{vo.phone}


	and cc.name = #{vo.name}


	and cc.lock_flag = #{vo.lockFlag}


	and cc.merchant_id = #{vo.merchantId}
